#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise the outer loop (each row is independent). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0;
        double sumB = 0.0;

        /* Use raw pointers for a small speed advantage. */
        const double* Ai = A[i].data();
        const double* Bi = B[i].data();
        const double* X  = x.data();

        for (int j = 0; j < n; ++j) {
            sumA += Ai[j] * X[j];
            sumB += Bi[j] * X[j];
        }

        tmp[i] = sumA;
        y[i]   = alpha * sumA + beta * sumB;
    }
}
