#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // => Form  B := alpha*A**T*B.
    // A is MxM
    // B is MxN

    // Parallelise over the outer two loops (i,j). This keeps the write
    // to B[i][j] private to each thread, guaranteeing repeatable
    // behaviour.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        const std::vector<double>& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            double sum = B[i][j];                // start with current value
            // Use a local reference to avoid repeated indexing
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * sum;               // final scaling
        }
    }
}
