#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    // Ensure the output and auxiliary vectors have the correct sizes
    y.assign(n, 0.0);
    tmp.resize(m);

    // Parallel over the rows of A; each iteration writes to its own tmp[i]
    // and updates the global y array which is reduced across threads.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double sum = 0.0;
        const double *a_row = A[i].data();      // pointer to the i‑th row
        const double *x_ptr = x.data();         // pointer to x
        // Compute the inner product for this row (tmp[i])
        for (int j = 0; j < n; ++j) {
            sum += a_row[j] * x_ptr[j];
        }
        tmp[i] = sum;

        // Update the result vector y (reduction happens across threads).
        // We use a temporary array to avoid race conditions.
        double *y_ptr = y.data();               // pointer to y
        for (int j = 0; j < n; ++j) {
            #pragma omp atomic
            y_ptr[j] += a_row[j] * sum;
        }
    }
}
