#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    // Parallelize the outer loop; each iteration is independent.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Cache row pointers to avoid repeated pointer arithmetic.
        double* row_i = A[i].data();

        /* First part: compute the elements below the diagonal in row i */
        for (int j = 0; j < i; ++j) {
            // Accumulate the dot product A[i][k] * A[k][j] for k = 0..j-1
            // Using a local variable to reduce the number of memory accesses.
            double sum = 0.0;
            double* row_i_k = row_i;
            for (int k = 0; k < j; ++k) {
                sum += row_i_k[k] * A[k][j];
            }
            row_i[j] = (row_i[j] - sum) / A[j][j];
        }

        /* Second part: compute the elements on and above the diagonal
           in row i (including the diagonal element which is unchanged). */
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += row_i[k] * A[k][j];
            }
            row_i[j] -= sum;
        }
    }
}
