```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {

    /* ----------------------------------------------------------------------
       1) Compute s[j] = Σ_i r[i] * A[i][j]
          Each s[j] is updated by all rows i -> race if done in parallel
          over i.  Parallelise over columns j instead.
    ---------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double acc = 0.0;
        for (int i = 0; i < n; ++i) {
            acc += r[i] * A[i][j];
        }
        s[j] = acc;
    }

    /* ----------------------------------------------------------------------
       2) Compute q[i] = Σ_j (A[i][j] + p[j])
          The summation for a given i is independent of others.
          Parallelise over rows i.
    ---------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double acc = 0.0;
        for (int j = 0; j < m; ++j) {
            acc += A[i][j] + p[j];
        }
        q[i] = acc;
    }
}
