trisolv:
```cpp
#include <vector>
#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    /* The algorithm is a classic forward substitution for a lower
       triangular system.  The outer loop cannot be parallelised
       because each iteration depends on all previous x values.
       The optimisation below focuses on the inner
       loop:  we keep a contiguous pointer to the current row of L
       and use a local sum variable to avoid repeated indexing.  */

    for (int i = 0; i < n; ++i) {
        double sum = b[i];                    // start with the RHS value
        const double* lrow = L[i].data();     // pointer to the i‑th row of L

        /* Unroll the inner loop in chunks of 8 to reduce loop‑overhead. */
        int j = 0;
        const int unroll = 8;
        const int lim = (i / unroll) * unroll;
        for (; j < lim; j += unroll) {
            sum -= (lrow[j]   * x[j]   +
                    lrow[j+1] * x[j+1] +
                    lrow[j+2] * x[j+2] +
                    lrow[j+3] * x[j+3] +
                    lrow[j+4] * x[j+4] +
                    lrow[j+5] * x[j+5] +
                    lrow[j+6] * x[j+6] +
                    lrow[j+7] * x[j+7]);
        }
        for (; j < i; ++j) {
            sum -= lrow[j] * x[j];
        }

        x[i] = sum / lrow[i];   // divide by the diagonal element
    }
}
