```cpp
#include <vector>
#include <cstdlib>
#include <cstring>
#include <xmmintrin.h>
#include <immintrin.h>
#include <omp.h>

/* Optimised Durbin kernel.
 * The interface is kept identical to the reference implementation. */
void kernel_durbin(int n, std::vector<double>& r, std::vector<double>& y)
{
    /* Allocate contiguous arrays on the heap (no std::vector overhead). */
    double* y_arr = (double*)_mm_malloc(n * sizeof(double), 64);
    double* z_arr = (double*)_mm_malloc(n * sizeof(double), 64);

    /* Initialise the first element. */
    y_arr[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        /* Update beta. */
        beta = (1.0 - alpha * alpha) * beta;

        /* Compute the dot‑product r[k‑i‑1] * y[i]. */
        double sum = 0.0;
        int i = 0;
        /* SIMD‑friendly loop (vectorised by the compiler). */
        for (; i + 3 < k; i += 4) {
            __m256d val1 = _mm256_loadu_pd(&r[k - i - 1]);   // r[k-i-1 .. k-i-4]
            __m256d val2 = _mm256_loadu_pd(&y_arr[i]);       // y[i .. i+3]
            __m256d mul  = _mm256_mul_pd(val1, val2);
            __m256d sum4 = _mm256_hadd_pd(mul, mul);
            double tmp   = sum4.m256d_f64[0] + sum4.m256d_f64[1];
            sum += tmp;
        }
        for (; i < k; ++i) {
            sum += r[k - i - 1] * y_arr[i];
        }

        /* Update alpha. */
        alpha = -(r[k] + sum) / beta;

        /* Compute new y values into z. */
        for (int j = 0; j < k; ++j) {
            z_arr[j] = y_arr[j] + alpha * y_arr[k - j - 1];
        }

        /* Copy back from z to y. */
        memcpy(y_arr, z_arr, k * sizeof(double));

        y_arr[k] = alpha;
    }

    /* Copy the result back to the caller's vector. */
    std::copy(y_arr, y_arr + n, y.begin());

    /* Free the temporary buffers. */
    _mm_free(y_arr);
    _mm_free(z_arr);
}
