gemm:
```cpp
#include <vector>
#include <omp.h>
#include <cmath>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Gather raw pointers to contiguous data for fast access
    const double *A_ptr = &A[0][0];
    const double *B_ptr = &B[0][0];
          double *C_ptr = &C[0][0];

    const int lda = nk;    // leading dimension of A
    const int ldb = nj;    // leading dimension of B
    const int ldc = nj;    // leading dimension of C

    // Cache‑friendly blocking sizes (tuned for a typical 2‑level cache)
    const int IB = 64;  // block size for i dimension
    const int KB = 64;  // block size for k dimension
    const int JB = 64;  // block size for j dimension

    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < ni; ii += IB)
    {
        int i_end = std::min(ii + IB, ni);
        for (int jj = 0; jj < nj; jj += JB)
        {
            int j_end = std::min(jj + JB, nj);
            // Scale the C block by beta once
            for (int i = ii; i < i_end; ++i)
            {
                double *C_row = C_ptr + i * ldc + jj;
                for (int j = 0; j < j_end - jj; ++j)
                    C_row[j] *= beta;
            }

            // Compute the product in blocks
            for (int kk = 0; kk < nk; kk += KB)
            {
                int k_end = std::min(kk + KB, nk);
                for (int i = ii; i < i_end; ++i)
                {
                    const double *A_row = A_ptr + i * lda + kk;
                    double *C_row = C_ptr + i * ldc + jj;
                    for (int k = kk; k < k_end; ++k)
                    {
                        double a_val = alpha * A_row[k - kk];
                        const double *B_row = B_ptr + k * ldb + jj;
                        for (int j = 0; j < j_end - jj; ++j)
                            C_row[j] += a_val * B_row[j];
                    }
                }
            }
        }
    }
}
