```cpp
#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* 1. Compute mean per column   */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    /* 2. Compute stddev per column  */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mu;
            sum += diff * diff;
        }
        double sdev = std::sqrt(sum / static_cast<double>(n));
        stddev[j] = (sdev <= eps) ? 1.0 : sdev;
    }

    /* 3. Center and scale data   */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double val = data[i][j] - mean[j];
            val *= inv_sqrt_n / stddev[j];
            data[i][j] = val;
        }
    }

    /* 4. Compute correlation matrix   */
    /* corr matrix is symmetric; fill upper triangle and mirror */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
}
