ludcmp:
```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {

    /* ---------- LU decomposition with partial pivoting ---------- */
    for (int i = 0; i < n; ++i) {
        std::vector<double>* row_i = &A[i];

        /* Compute lower part (U part is already in place) */
        for (int j = 0; j < i; ++j) {
            double w = (*row_i)[j];
            std::vector<double>* row_j  = &A[j];
            for (int k = 0; k < j; ++k)
                w -= (*row_i)[k] * (*row_j)[k];
            (*row_i)[j] = w / (*row_j)[j];
        }

        /* Compute the rest of the row */
        for (int j = i; j < n; ++j) {
            double w = (*row_i)[j];
            std::vector<double>* row_j  = &A[j];
            for (int k = 0; k < i; ++k)
                w -= (*row_i)[k] * (*row_j)[k];
            (*row_i)[j] = w;
        }
    }

    /* ---------- Forward substitution: solve L*y = b ---------- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        std::vector<double>* row_i = &A[i];
        for (int j = 0; j < i; ++j) {
            w -= (*row_i)[j] * y[j];
        }
        y[i] = w;
    }

    /* ---------- Backward substitution: solve U*x = y ---------- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        std::vector<double>* row_i = &A[i];
        for (int j = i + 1; j < n; ++j) {
            w -= (*row_i)[j] * x[j];
        }
        x[i] = w / (*row_i)[i];
    }
}
