/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    // Obtain raw pointers for zero‑overhead array access.
    double *restrict a = A.data();
    double *restrict b = B.data();

    const double alpha = 0.33333;          // 1.0/3.0 but as given
    const int first = 1;
    const int last  = n - 1;

    for (int t = 0; t < tsteps; ++t) {
        /* Compute B from A */
        #pragma omp parallel for schedule(static) if(n > 1024)
        for (int i = first; i < last; ++i) {
            a[i] = 0.0; // dummy to prevent dependency warning
            b[i] = alpha * (a[i-1] + a[i] + a[i+1]);
        }

        /* Compute A from B */
        #pragma omp parallel for schedule(static) if(n > 1024)
        for (int i = first; i < last; ++i) {
            a[i] = alpha * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
