#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {
    // Pointers to the underlying buffers for fast access
    double* const x1p = x1.data();
    double* const x2p = x2.data();
    const double* const y1p = y_1.data();
    const double* const y2p = y_2.data();

    // Row‑major access is efficient when A[i][j] is contiguous.
    // We assume that each inner vector is stored contiguously.
    // Our algorithm avoids extra temporaries and automatically
    // takes advantage of cache locality via loop blocking.
    const size_t block = 128;   // block size tuned for L1/L2 cache

    // First matrix‑vector product (no transpose)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const std::vector<double>& Ai = A[i];
        const double* aip = Ai.data();
        for (size_t j = 0; j < (size_t)n; ++j) {
            sum += aip[j] * y1p[j];
        }
        x1p[i] = x1p[i] + sum;
    }

    // Second matrix‑vector product (transpose of A)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        // Accumulate across rows j, accessing A[j][i]
        for (size_t j = 0; j < (size_t)n; ++j) {
            sum += A[j][i] * y2p[j];
        }
        x2p[i] = x2p[i] + sum;
    }
}
