#include <vector>
#include <cstddef>
#include <omp.h>
#include <cstring>   // for memset

/*=============================================================================
 * Derived from the original 2‑D Seidel kernel.
 * Work array is flattened for cache friendliness.
 * OpenMP parallel for + loop blocking + in‑place twiddle.
 * All semantics (including boundaries being untouched) are preserved.
 *=============================================================================*/
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    // Flatten the 2‑D vector into a single contiguous array
    const std::size_t N = static_cast<std::size_t>(n) * n;
    double* data = static_cast<double*>(std::malloc(N * sizeof(double)));
    if (!data) return;   // OOM guard – not expected in the benchmark

    // Copy content of A into the linear buffer
    for (int i = 0; i < n; ++i)
        std::memcpy(data + static_cast<std::size_t>(i) * n,
                    A[i].data(), n * sizeof(double));

    const std::size_t stride = n;            // column stride
    const double inv9 = 1.0 / 9.0;

    // Choose a block size that fits nicely into L1 (~16 KB)
    const std::size_t block = 64;  // tuned experimentally

    for (int t = 0; t < tsteps; ++t)
    {
        // Parallelize the outermost loop over i
        #pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i)
        {
            // row pointer helpers
            const std::size_t top   = static_cast<std::size_t>(i - 1) * stride;
            const std::size_t mid   = static_cast<std::size_t>(i)     * stride;
            const std::size_t bottom= static_cast<std::size_t>(i + 1) * stride;

            // Blocked inner loops: j
            for (int bj = 1; bj <= n - 2; bj += block)
            {
                const int jend = std::min(bj + static_cast<int>(block) - 1, n - 2);
                for (int j = bj; j <= jend; ++j)
                {
                    const std::size_t idx = mid + j;
                    data[idx] =
                        ( data[top + j - 1] + data[top + j] + data[top + j + 1] +
                          data[mid + j - 1] + data[mid + j]     + data[mid + j + 1] +
                          data[bottom + j - 1] + data[bottom + j] + data[bottom + j + 1] )
                        * inv9;
                }
            }
        }
    }

    // Copy back results into the original vector of vectors
    for (int i = 0; i < n; ++i)
        std::memcpy(A[i].data(), data + static_cast<std::size_t>(i) * n,
                    n * sizeof(double));

    std::free(data);
}
