#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    /* Parallelise over columns j.  Each column is independent so
       there are no races in the updates to C.  The inner loop over
       i is left serial to preserve the order of updates to the
       lower‑triangular part of C.  */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        for (int i = 0; i < m; ++i) {
            double temp = 0.0;
            double bj = B[i][j];
            double ai_i = A[i][i];
            auto& Ci = C[i];
            for (int k = 0; k < i; ++k) {
                double aik = A[i][k];
                double bk = B[k][j];
                C[k][j] += alpha * bj * aik;
                temp += bk * aik;
            }
