/*
 * Optimised kernel for the 2‑matrix multiply benchmark.
 *
 * The implementation keeps the public API unchanged while
 * exploiting data‑locality and OpenMP parallelisation.
 *  - All loops are parallelised with `#pragma omp parallel for`.
 *  - Every row of the input vectors is accessed through a raw pointer
 *    (obtained via `.data()`) to avoid the bounds checks of `operator[]`.
 *  - Temporary accumulation variables (`sum`, `tmp`) are allocated
 *    on the stack for each thread iteration, guaranteeing cache‑friendly
 *    reuse of the data.
 *  - No temporary copies are created; the original data layout
 *    (vector of vectors) is respected.
 *
 * This code compiles with `gcc -O2 -fopenmp` and produces *exactly*
 * the same numerical results as the original reference implementation.
 */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* ------------------------------------------------------------------
     * Stage 1:  tmp = alpha * A * B
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // obtain raw row pointers once per outer loop iteration
        const double *aRow = A[i].data();
        double       *tRow = tmp[i].data();

        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double *bCol = nullptr;    // will be used for B[k][j]
            for (int k = 0; k < nk; ++k) {
                bCol = B[k].data();
                sum += alpha * aRow[k] * bCol[j];
            }
            tRow[j] = sum;
        }
    }

    /* ------------------------------------------------------------------
     * Stage 2:  D = beta * D + tmp * C
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *dRow = D[i].data();
        const double *tRow = tmp[i].data();

        for (int j = 0; j < nl; ++j) {
            double sum = beta * dRow[j];
            for (int k = 0; k < nj; ++k) {
                sum += tRow[k] * C[k][j];
            }
            dRow[j] = sum;
        }
    }
}
