   Flattened 2‑D array C4: C4[s][p] -> C4[s*np + p]     */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    const std::size_t szAz = static_cast<std::size_t>(nr) * nq * np;
    const std::size_t szC4 = static_cast<std::size_t>(np) * np;

    // Allocate flattened copies if not already flattened
    std::vector<double> flatA(szAz);
    std::vector<double> flatC4(szC4);

    // Copy into flattened memory (assuming small overhead acceptable)
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            for (int s = 0; s < np; ++s)
                flatA[(static_cast<std::size_t>(r)*nq + q)*np + s]
                    = A[r][q][s];

    for (int s = 0; s < np; ++s)
        for (int p = 0; p < np; ++p)
            flatC4[s*np + p] = C4[s][p];

    // Main computation
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // base index for A[r][q][*]
            std::size_t aBase = (static_cast<std::size_t>(r)*nq + q)*np;
            // Compute sum[p] = Σ_s A[r][q][s] * C4[s][p]
            for (int p = 0; p < np; ++p) {
                double val = 0.0;
                for (int s = 0; s < np; ++s) {
                    val += flatA[aBase + s] * flatC4[s*np + p];
                }
                sum[p] = val;
            }
            // Write back
            for (int p = 0; p < np; ++p) {
                flatA[aBase + p] = sum[p];
            }
        }
    }

    // Copy result back into original nested vectors
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            for (int s = 0; s < np; ++s)
                A[r][q][s] = flatA[(static_cast<std::size_t>(r)*nq + q)*np + s];
}
