#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Remove synchronisation points within each outer loop
    for (int k = 0; k < n; ++k) {
        // Compute norm of column k of A
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double a = A[i][k];
            nrm += a * a;
        }
        R[k][k] = std::sqrt(nrm);

        // Normalise column k to form column k of Q
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        // Orthogonalise columns k+1..n-1
#pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            // Compute R[k][j] = dot(Q(:,k), A(:,j))
            double rkj = 0.0;
#pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            // Update A(:,j) = A(:,j) - Q(:,k) * R[k][j]
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rkj;
            }
        }
    }
}
