/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    const double coeff = 0.2;               // constant factor
    const int inner_start = 1;              // start index for inner cells
    const int inner_end   = n - 2;          // end index for inner cells

    for (int t = 0; t < tsteps; ++t)
    {
        /* ---- first sweep : A -> B ------------------------------------- */
#pragma omp parallel for schedule(static, 8) collapse(1)
        for (int i = inner_start; i <= inner_end; ++i)
        {
            double* Arow     = A[i].data();
            double* Aprevrow = A[i - 1].data();
            double* Arownext = A[i + 1].data();

            double* Brow     = B[i].data();
            double* Bprevrow = B[i - 1].data();
            double* Brownext = B[i + 1].data();

            for (int j = inner_start; j <= inner_end; ++j)
            {
                Brow[j] = coeff * (Arow[j] + Arow[j - 1] + Arow[j + 1] +
                                   Arownext[j] + Aprevrow[j]);
            }
        }

        /* ---- second sweep : B -> A ------------------------------------ */
#pragma omp parallel for schedule(static, 8) collapse(1)
        for (int i = inner_start; i <= inner_end; ++i)
        {
            double* Brow     = B[i].data();
            double* Bprevrow = B[i - 1].data();
            double* Brownext = B[i + 1].data();

            double* Arow     = A[i].data();
            double* Aprevrow = A[i - 1].data();
            double* Arownext = A[i + 1].data();

            for (int j = inner_start; j <= inner_end; ++j)
            {
                Arow[j] = coeff * (Brow[j] + Brow[j - 1] + Brow[j + 1] +
                                   Brownext[j] + Bprevrow[j]);
            }
        }
    }
}
