#include <cstddef>   // for size_t

// Fully contiguous storage for 2D matrices
template <class T>
class Matrix {
public:
    Matrix(std::size_t rows, std::size_t cols)
        : rows_(rows), cols_(cols), data_(rows * cols) {}

    T& operator()(std::size_t i, std::size_t j) {
        return data_[i * stride_ + j];
    }
    const T& operator()(std::size_t i, std::size_t j) const {
        return data_[i * stride_ + j];
    }

    T* row_ptr(std::size_t i) { return data_.data() + i * stride_; }
    const T* row_ptr(std::size_t i) const { return data_.data() + i * stride_; }

    std::size_t rows() const { return rows_; }
    std::size_t cols() const { return cols_; }

private:
    std::size_t rows_, cols_;
    std::size_t stride_ = 0;  // will be set after construction
    std::vector<T> data_;
};

void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Flatten the input vectors into contiguous buffers
    Matrix<double> Cmat(n, n), Amat(n, m), Bmat(n, m);
    for (int i = 0; i < n; ++i) {
        std::copy(C[i].begin(), C[i].end(), Cmat.row_ptr(i));
        std::copy(A[i].begin(), A[i].end(), Amat.row_ptr(i));
        std::copy(B[i].begin(), B[i].end(), Bmat.row_ptr(i));
    }

    // Make the data contiguous so the compiler can apply optimizations
    Cmat.stride_ = n;
    Amat.stride_ = m;
    Bmat.stride_ = m;

    const double a = alpha;
    const double b = beta;

    // Parallel over outer index i
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* c_row = Cmat.row_ptr(i);
        const double* a_row = Amat.row_ptr(i);
        const double* b_row = Bmat.row_ptr(i);

        // First scale the lower triangle  (j <= i)
        for (int j = 0; j <= i; ++j) {
            c_row[j] *= b;
        }

        // Accumulate the rank‑2 update for this row
        for (int k = 0; k < m; ++k) {
            double aik = a_row[k] * a;
            double bik = b_row[k] * a;
            const double* a_col = Amat.row_ptr(0) + k;
            const double* b_col = Bmat.row_ptr(0) + k;

            for (int j = 0; j <= i; ++j) {
                c_row[j] += a_col[j] * b_row[k] + b_col[j] * aik;
            }
        }
    }

    // Copy results back into the original nested vectors
    for (int i = 0; i < n; ++i) {
        std::copy(Cmat.row_ptr(i), Cmat.row_ptr(i) + n, C[i].begin());
    }
}
