/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    /* Allocate a contiguous buffer and copy the 2-D data into it.
       The buffer is indexed with a single formula  i*n + j. */
    const int size = n * n;
    std::vector<double> flat(size);

    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flat.begin() + i * n);

    /* Parallelise the outermost loop; the loops below are
       cache‑friendly as they walk the matrix row‑by‑row. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const int ioff = i * n;          // offset of row i
        /* j < i  : compute the off‑diagonal elements */
        for (int j = 0; j < i; ++j) {
            double value = flat[ioff + j];
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += flat[ioff + k] * flat[j * n + k];
            }
            value -= sum;
            value /= flat[j * n + j];
            flat[ioff + j] = value;
        }

        /* i == i  : compute the diagonal element */
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            double val = flat[ioff + k];
            sum += val * val;
        }
        double diag = flat[ioff + i] - sum;
        flat[ioff + i] = std::sqrt(diag);
    }

    /* Copy the result back to the original 2‑D vector. */
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n,
                  flat.begin() + (i + 1) * n,
                  A[i].begin());
}
