/// 1‑D representation of a square matrix in row major order.
/// Non‑modified API is kept: path is a vector of vector<int>.
/// Internally we copy it into a flat array for better cache usage,
/// perform the computation, then copy the result back.
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Allocate a flat buffer of size n*n
    std::vector<int> flat(n * n);

    // Flatten the input matrix
    for (int i = 0; i < n; ++i) {
        std::memcpy(&flat[i * n], path[i].data(), n * sizeof(int));
    }

    // The main triple loop – the k‑loop is kept serial because
    // all updates in an iteration depend on the previous value of `path[i][k]`
    // and `path[k][j]`.  The i‑ and j‑loops are independent and can be
    // parallelised safely.
    for (int k = 0; k < n; ++k) {
        const int* rowk = &flat[k * n];            // pointer to row k
        // Parallelise over rows i
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int* rowi = &flat[i * n];             // pointer to row i
            int ik = rowi[k];                     // path[i][k]
            // Unroll inner j‑loop in small chunks for better pipeline usage
            int j = 0;
            for (; j <= n - 8; j += 8) {
                int t0 = ik + rowk[j];
                int t1 = ik + rowk[j + 1];
                int t2 = ik + rowk[j + 2];
                int t3 = ik + rowk[j + 3];
                int t4 = ik + rowk[j + 4];
                int t5 = ik + rowk[j + 5];
                int t6 = ik + rowk[j + 6];
                int t7 = ik + rowk[j + 7];
                rowi[j]     = std::min(rowi[j],     t0);
                rowi[j + 1] = std::min(rowi[j + 1], t1);
                rowi[j + 2] = std::min(rowi[j + 2], t2);
                rowi[j + 3] = std::min(rowi[j + 3], t3);
                rowi[j + 4] = std::min(rowi[j + 4], t4);
                rowi[j + 5] = std::min(rowi[j + 5], t5);
                rowi[j + 6] = std::min(rowi[j + 6], t6);
                rowi[j + 7] = std::min(rowi[j + 7], t7);
            }
            // Handle remaining columns
            for (; j < n; ++j) {
                int t = ik + rowk[j];
                rowi[j] = std::min(rowi[j], t);
            }
        }
    }

    // Copy the resulting data back into the original 2‑D vector
    for (int i = 0; i < n; ++i) {
        std::memcpy(path[i].data(), &flat[i * n], n * sizeof(int));
    }
}
