/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Assume that each row of C and A is a contiguous N–element vector.
    // The algorithm is split into two phases so that the β‑multiplication
    // can be parallelised independently from the α‑accumulation.
    //
    // 1) Scale the lower triangle of C by β.
    // 2) Compute C := α·A·Aᵀ + β·C by accumulating over the columns of A.
    //
    // OpenMP is used with a cooperative schedule so that iterations that
    // touch different rows of C are independent.  The β‑phase is split into
    // a parallel for over i with as many threads as available.  The α‑phase
    // is a nested loop over i → k → j; the innermost loop is the critical
    // one because it writes to C[i][j].
    //
    // Data layout assumption:  C[i] and A[i] point to contiguous memory of
    // size n (for C) and m (for A).  This allows using raw pointers
    // inside the loops for maximum cache friendliness.

    // 1) Scale lower triangle of C by β in parallel.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Ci = C[i].data();
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }
    }

    // 2) Accumulate α·A·Aᵀ contribution to the lower triangle.
    //    Loop order: i → k → j.  This keeps the read of A[j][k] in
    //    inner loop, enabling better cache reuse when j advances.
    //    The outer loop over i can also be parallelised.  Since each
    //    thread works on a distinct row i, no data races occur.
    constexpr int BLOCK = 32;   // block size for better cache utilisation
    for (int ii = 0; ii < n; ii += BLOCK) {
        int i_end = std::min(ii + BLOCK, n);
#pragma omp parallel for schedule(static)
        for (int i = ii; i < i_end; ++i) {
            double *Ci = C[i].data();
            double *Ai = A[i].data();
            for (int k = 0; k < m; ++k) {
                double aik = alpha * Ai[k];
                // j runs only up to i (lower triangle)
                for (int j = 0; j <= i; ++j) {
                    Ci[j] += aik * A[j][k];
                }
            }
        }
    }
}
