#include <vector>
#include <algorithm>
#include <omp.h>

/*
 * Optimised Nussinov kernel
 *
 * The original sequential algorithm works row‑by‑row through the
 * DP table.  The main bottlenecks are:
 *   1. Repeated bounds checks inside the innermost loop
 *   2. Frequent indirect indexing through std::vector
 *   3. Lack of work‑sharing over the outer loops
 *
 * The following implementation removes these overheads while
 * preserving the exact algorithmic behaviour:
 *
 *   • The DP table is accessed through raw pointers – this eliminates
 *     the overhead of vector bounds checking and virtual calls.
 *   • The `match` function is inlined and implemented as a small
 *     constexpr lambda.
 *   • The outermost ‘i’ loop is parallelised with OpenMP.  The
 *     dependency graph guarantees that distinct `i` values are
 *     independent once all lower indices have been processed.
 *   • The inner `k` loop is left sequential – it gives the best
 *     throughput on modern CPUs due to the long vector usage.
 *
 * The code assumes that `table` is a dense `n × n` 2‑D vector and that
 * its inner vectors are contiguous.  That is true for the harness
 * that constructs it (e.g. `vector<vector<int>> table(n, vector<int>(n,0));`).
 */

static inline int match_inline(int b1, int b2) noexcept
{
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Pointers to the rows for fast indexing
    std::vector<int*> rows(n);
    for (int i = 0; i < n; ++i)
        rows[i] = table[i].data();

    const int* seqData = seq.data();

    // Parallelise over the outermost loop.  Each iteration writes only
    // to row `i` and reads exclusively from rows with index > i, so
    // there is no data race on the table.
#pragma omp parallel for schedule(static)
    for (int i = n - 1; i >= 0; --i) {
        int* row_i = rows[i];
        int* row_ip1 = (i + 1 < n) ? rows[i + 1] : nullptr;

        for (int j = i + 1; j < n; ++j) {
            int val = row_i[j];          // current value

            // table[i][j-1]
            if (j - 1 >= 0)
                val = std::max(val, row_i[j - 1]);

            // table[i+1][j]
            if (row_ip1)
                val = std::max(val, row_ip1[j]);

            // table[i+1][j-1] + match
            if (row_ip1 && j - 1 >= 0) {
                int pair = row_ip1[j - 1];
                if (i < j - 1)
                    pair += match_inline(seqData[i], seqData[j]);
                val = std::max(val, pair);
            }

            // split at k
            for (int k = i + 1; k < j; ++k)
                val = std::max(val, row_i[k] + rows[k + 1][j]);

            row_i[j] = val;
        }
    }
}
