/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {

    /* Work with raw pointers for maximum speed.  */
    double *const *A_ptr      = reinterpret_cast<const double **>( &A[0] );
    double *const   u1_ptr    = u1.data();
    double *const   v1_ptr    = v1.data();
    double *const   u2_ptr    = u2.data();
    double *const   v2_ptr    = v2.data();
    double *const   w_ptr     = w.data();
    double *const   x_ptr     = x.data();
    double *const   y_ptr     = y.data();
    double *const   z_ptr     = z.data();

    /* -----------------------------------------------------------------
       1) A[i][j] += u1[i]*v1[j] + u2[i]*v2[j]
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1 = u1_ptr[i];
        const double ui2 = u2_ptr[i];
        double *Ai      = const_cast<double*>(A_ptr[i]);  /* row i */

        for (int j = 0; j < n; ++j)
            Ai[j] += ui1 * v1_ptr[j] + ui2 * v2_ptr[j];
    }

    /* -----------------------------------------------------------------
       2) x[i] += beta * sum_j A[j][i] * y[j]
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j)
            sum += A_ptr[j][i] * y_ptr[j];
        x_ptr[i] += beta * sum;
    }

    /* -----------------------------------------------------------------
       3) x[i] += z[i]
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        x_ptr[i] += z_ptr[i];

    /* -----------------------------------------------------------------
       4) w[i] += alpha * sum_j A[i][j] * x[j]
       ----------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
