        ex_ptr[i] = ex[i].data();
        ey_ptr[i] = ey[i].data();
        hz_ptr[i] = hz[i].data();
    }

    for (int t = 0; t < tmax; ++t) {
        // Update ey[0][j] – only boundary row
        #pragma omp simd
        for (int j = 0; j < ny; ++j)
            ey_ptr[0][j] = _fict_[t];

        // Update ey[i][j] for i >= 1
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < nx; ++i) {
            double* ey_i   = ey_ptr[i];
            double* ey_prev= ey_ptr[i-1];
            double* hz_i   = hz_ptr[i];
            double* hz_prev= hz_ptr[i-1];
            for (int j = 0; j < ny; ++j) {
                ey_i[j] -= 0.5 * (hz_i[j] - hz_prev[j]);
