            double* ex_i   = ex_ptr[i];
            double* hz_i   = hz_ptr[i];
            for (int j = 1; j < ny; ++j) {
                ex_i[j] -= 0.5 * (hz_i[j] - hz_i[j-1]);
            }
        }

        // Update hz[i][j] for i < nx-1 and j < ny-1
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < nx-1; ++i) {
            double* hz_i   = hz_ptr[i];
            double* ex_i   = ex_ptr[i];
            double* ey_ip1 = ey_ptr[i+1];
            double* ey_i   = ey_ptr[i];
