#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Optimised for gcc -O2 with OpenMP support. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /*--- Pre‑compute constants (float is sufficient for the former
        double precision in the original code). ---------------------------------*/
    const float E_minus_a  = std::expf(-static_cast<float>(alpha));
    const float E_minus_2a = E_minus_a * E_minus_a;
    const float denom = 1.0f + 2.0f * static_cast<float>(alpha) * E_minus_a - E_minus_2a;
    const float k = 1.0f - E_minus_a * (1.0f - E_minus_a) / denom;

    const float a1 = k, a5 = k;
    const float a2 = k * E_minus_a * (static_cast<float>(alpha) - 1.0f);
    const float a6 = a2;
    const float a3 = k * E_minus_a * (static_cast<float>(alpha) + 1.0f);
    const float a7 = a3;
    const float a4 = -k * E_minus_2a, a8 = a4;

    const float b1 = std::powf(2.0f, -static_cast<float>(alpha));
    const float b2 = -E_minus_2a;
    const float c1 = 1.0f, c2 = 1.0f;   // unchanged

    /*--- Row filtering – forward pass (parallelisable across rows). ---------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f;
        float xm1 = 0.0f;
        float* src = imgIn[i].data();
        float* dst = y1[i].data();

        for (int j = 0; j < h; ++j) {
            const float x = src[j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            dst[j] = y;
            xm1 = x;          // input for next step
            ym2 = ym1;        // hold previous output
            ym1 = y;
        }
    }

    /*--- Row filtering – backward pass -------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f;
        float xp1 = 0.0f, xp2 = 0.0f;
        const float* src = imgIn[i].data();
        float* dst = y2[i].data();

        for (int j = h - 1; j >= 0; --j) {
            const float x = src[j];
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            dst[j] = y;
            xp2 = xp1;
            xp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /*--- Combine two directional responses (forward + backward). -----------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /*--- Column filtering – forward pass -----------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float in = imgOut[i][j];
            const float y = a5 * in + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = in;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /*--- Column filtering – backward pass ----------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float in = imgOut[i][j];
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;
            tp1 = in;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /*--- Final output (sum of both directional responses). ---------------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
